    private static async Task<object> ExecuteDatabaseQuery(string requestId, string userId, ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        log.LogInformation($"[{requestId}] Database Connection String: {connectionString}");

        string query = @"
            SELECT u.UserId, u.Username, u.Email, u.PasswordHash, u.CreditCardNumber, u.SSN, u.DateOfBirth, 
                   a.Street, a.City, a.State, a.ZipCode, a.Country,
                   o.OrderId, o.OrderDate, o.TotalAmount
            FROM Users u
            LEFT JOIN Addresses a ON u.UserId = a.UserId
            LEFT JOIN Orders o ON u.UserId = o.UserId
            WHERE u.UserId = @UserId";

        log.LogInformation($"[{requestId}] Executing SQL Query: {query}");
        log.LogInformation($"[{requestId}] SQL Parameter - @UserId: {userId}");

        var results = new List<Dictionary<string, object>>();

        try
        {
            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                log.LogInformation($"[{requestId}] Database connection opened successfully");
                log.LogInformation($"[{requestId}] Database Server: {connection.DataSource}");
                log.LogInformation($"[{requestId}] Database Name: {connection.Database}");

                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    command.Parameters.AddWithValue("@UserId", userId ?? (object)DBNull.Value);
                    
                    log.LogInformation($"[{requestId}] Command timeout: {command.CommandTimeout}");
                    log.LogInformation($"[{requestId}] Command type: {command.CommandType}");

                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        log.LogInformation($"[{requestId}] Query executed, reading results...");
                        
                        int rowCount = 0;
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                string columnName = reader.GetName(i);
                                object value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                                row[columnName] = value;
                                
                                log.LogInformation($"[{requestId}] Row {rowCount}, Column '{columnName}': {value}");
                            }
                            results.Add(row);
                            rowCount++;
                        }
                        
                        log.LogInformation($"[{requestId}] Total rows retrieved: {rowCount}");
                    }
                }
            }
        }
        catch (SqlException sqlEx)
        {
            log.LogError(sqlEx, $"[{requestId}] SQL Exception occurred");
            log.LogError($"[{requestId}] SQL Error Number: {sqlEx.Number}");
            log.LogError($"[{requestId}] SQL Error State: {sqlEx.State}");
            log.LogError($"[{requestId}] SQL Error Class: {sqlEx.Class}");
            log.LogError($"[{requestId}] SQL Error Server: {sqlEx.Server}");
            log.LogError($"[{requestId}] SQL Error Procedure: {sqlEx.Procedure}");
            log.LogError($"[{requestId}] SQL Error Line Number: {sqlEx.LineNumber}");
            
            foreach (SqlError error in sqlEx.Errors)
            {
                log.LogError($"[{requestId}] SQL Error Detail - Message: {error.Message}, Number: {error.Number}, State: {error.State}");
            }
            
            throw;
